 {"id":"bd-5cza","title":"[Web] Implement Request Extractors","description":"## Overview

Implement a comprehensive set of extractors that can pull typed data from HTTP requests. Extractors are the primary mechanism for handlers to access request data in a type-safe way.

## Implementation Steps

### Step 1: Create FromRequest Trait

```rust
// src/web/extract/mod.rs

use crate::http::Request;
use crate::web::router::PathParams;
use std::future::Future;

/// Error type for extraction failures.
#[derive(Debug)]
pub struct Rejection {
    status: StatusCode,
    message: String,
}

impl Rejection {
    pub fn bad_request(msg: impl Into<String>) -> Self {
        Self { status: StatusCode::BAD_REQUEST, message: msg.into() }
    }

    pub fn not_found(msg: impl Into<String>) -> Self {
        Self { status: StatusCode::NOT_FOUND, message: msg.into() }
    }
}

impl IntoResponse for Rejection {
    fn into_response(self) -> Response {
        Response::builder()
            .status(self.status)
            .body(self.message)
            .unwrap()
    }
}

/// Trait for extracting data from request parts (headers, path, query).
pub trait FromRequestParts<S = ()>: Sized {
    type Rejection: IntoResponse;

    fn from_request_parts(
        req: &Request,
        params: &PathParams,
        state: &S,
    ) -> impl Future<Output = Result<Self, Self::Rejection>> + Send;
}

/// Trait for extracting data from the full request (may consume body).
pub trait FromRequest<S = ()>: Sized {
    type Rejection: IntoResponse;

    fn from_request(
        req: Request,
        params: &PathParams,
        state: &S,
    ) -> impl Future<Output = Result<Self, Self::Rejection>> + Send;
}
```

### Step 2: Implement Path Extractor

```rust
// src/web/extract/path.rs

/// Extract typed path parameters.
///
/// # Example
/// ```rust
/// async fn get_user(Path(id): Path<u32>) -> String {
///     format!("User {}", id)
/// }
/// ```
#[derive(Debug, Clone)]
pub struct Path<T>(pub T);

impl<T, S> FromRequestParts<S> for Path<T>
where
    T: DeserializeOwned + Send,
    S: Sync,
{
    type Rejection = Rejection;

    async fn from_request_parts(
        _req: &Request,
        params: &PathParams,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        // Convert PathParams to map and deserialize
        let parsed: T = serde_path_to_error::deserialize(params)
            .map_err(|e| Rejection::bad_request(format!("invalid path: {}", e)))?;
        Ok(Path(parsed))
    }
}
```

### Step 3: Implement Query Extractor

```rust
// src/web/extract/query.rs

/// Extract typed query parameters.
#[derive(Debug, Clone)]
pub struct Query<T>(pub T);

impl<T, S> FromRequestParts<S> for Query<T>
where
    T: DeserializeOwned + Send,
    S: Sync,
{
    type Rejection = Rejection;

    async fn from_request_parts(
        req: &Request,
        _params: &PathParams,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let query_string = req.uri().query().unwrap_or("");
        let parsed: T = serde_urlencoded::from_str(query_string)
            .map_err(|e| Rejection::bad_request(format!("invalid query: {}", e)))?;
        Ok(Query(parsed))
    }
}
```

### Step 4: Implement JSON Body Extractor

```rust
// src/web/extract/json.rs

const DEFAULT_JSON_LIMIT: usize = 2 * 1024 * 1024;

/// Extract typed JSON body.
#[derive(Debug, Clone)]
pub struct Json<T>(pub T);

impl<T, S> FromRequest<S> for Json<T>
where
    T: DeserializeOwned + Send,
    S: Sync,
{
    type Rejection = Rejection;

    async fn from_request(
        req: Request,
        _params: &PathParams,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        // Check content type
        let content_type = req.headers()
            .get("content-type")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("");

        if !content_type.starts_with("application/json") {
            return Err(Rejection::bad_request("expected application/json"));
        }

        // Read body with limit
        let bytes = req.into_body()
            .collect_with_limit(DEFAULT_JSON_LIMIT)
            .await
            .map_err(|_| Rejection::bad_request("body too large"))?;

        let parsed: T = serde_json::from_slice(&bytes)
            .map_err(|e| Rejection::bad_request(format!("invalid JSON: {}", e)))?;

        Ok(Json(parsed))
    }
}
```

### Step 5: Implement Form Extractor

```rust
// src/web/extract/form.rs

/// Extract URL-encoded form data.
#[derive(Debug, Clone)]
pub struct Form<T>(pub T);

impl<T, S> FromRequest<S> for Form<T>
where
    T: DeserializeOwned + Send,
    S: Sync,
{
    type Rejection = Rejection;

    async fn from_request(
        req: Request,
        _params: &PathParams,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let content_type = req.headers()
            .get("content-type")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("");

        if !content_type.starts_with("application/x-www-form-urlencoded") {
            return Err(Rejection::bad_request("expected form data"));
        }

        let bytes = req.into_body().collect().await
            .map_err(|e| Rejection::internal(format!("read error: {}", e)))?;

        let parsed: T = serde_urlencoded::from_bytes(&bytes)
            .map_err(|e| Rejection::bad_request(format!("invalid form: {}", e)))?;

        Ok(Form(parsed))
    }
}
```

### Step 6: Implement State Extractor

```rust
// src/web/extract/state.rs

/// Extract shared application state.
#[derive(Debug, Clone, Copy)]
pub struct State<S>(pub S);

impl<S> Deref for State<S> {
    type Target = S;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl<S> FromRequestParts<S> for State<S>
where
    S: Clone + Send + Sync,
{
    type Rejection = std::convert::Infallible;

    async fn from_request_parts(
        _req: &Request,
        _params: &PathParams,
        state: &S,
    ) -> Result<Self, Self::Rejection> {
        Ok(State(state.clone()))
    }
}
```

### Step 7: Implement Header Extractors

```rust
// src/web/extract/header.rs

/// Extract all headers as a map.
#[derive(Debug, Clone)]
pub struct HeaderMap(pub http::HeaderMap);

impl<S> FromRequestParts<S> for HeaderMap
where
    S: Sync,
{
    type Rejection = std::convert::Infallible;

    async fn from_request_parts(
        req: &Request,
        _params: &PathParams,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        Ok(HeaderMap(req.headers().clone()))
    }
}
```

## Cancel-Safety Considerations

- Path, Query, State extractors are synchronous - inherently cancel-safe
- Body-consuming extractors (Json, Form) read full body before parsing
- If cancelled mid-read, body is discarded (no state mutation)

