```rust
#[test]
fn e2e_interval_patterns() {
    setup_test_logging();

    let rt = LabRuntime::new();
    rt.block_on(async {
        info!("Starting interval patterns E2E test");

        // Pattern 1: Regular heartbeat
        info!("Testing regular heartbeat");
        let mut heartbeat = interval(Duration::from_millis(100));
        let mut count = 0;

        let start = Instant::now();
        while count < 5 {
            heartbeat.tick().await;
            count += 1;
            info!(tick = count, elapsed = ?start.elapsed(), "Heartbeat");
        }

        let elapsed = start.elapsed();
        assert!(elapsed >= Duration::from_millis(400));
        assert!(elapsed < Duration::from_millis(600));
        info!("Regular heartbeat verified");

        // Pattern 2: Rate-limited operations
        info!("Testing rate-limited operations");
        let mut rate_limiter = interval(Duration::from_millis(50));
        let operations = vec!["op1", "op2", "op3"];

        for op in operations {
            rate_limiter.tick().await;
            info!(operation = op, "Executing rate-limited operation");
        }
        info!("Rate limiting verified");

        // Pattern 3: Combined with timeout
        info!("Testing interval with timeout");
        let mut interval = interval(Duration::from_millis(200));
        let result = timeout(Duration::from_millis(500), async {
            let mut count = 0;
            loop {
                interval.tick().await;
                count += 1;
                if count > 10 { break count; }
            }
        }).await;

        // Should timeout after ~2 ticks
        assert!(result.is_err());
        info!("Interval with timeout verified");

        info!("E2E test completed successfully");
    });
}
